INSERT OR IGNORE INTO `item_types` (`id`, `name`, `description`, `color`, `icon`, `guidance`, `is_system`, `sort_order`, `created_at`, `updated_at`) VALUES ('a23da5fe-fc05-45ef-8236-28cf3a014984', 'P0 — Critical', 'Total outage or data loss affecting all users', '#DC2626', '🔴', '{"pattern":"[Service] + [impact] + [duration or status]","example":"API Gateway — complete outage, all requests returning 503 for 45 minutes","whenToUse":"Use for total service outages, data loss, or security breaches affecting all users","contentHints":"Include timeline (detected, escalated, resolved), impact scope, root cause, and remediation. Use headings for each phase."}', 1, 0, '2026-03-27T01:22:49.500Z', '2026-03-27T01:22:49.500Z');
