-- incidents-specific settings
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_title', 'My Incident Log', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_description', 'Production incident history and post-mortems', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Lead with the affected service, then the impact. Be specific about scope (all users, 10% of requests, single region)."},"content":{"tips":"Structure as a timeline: detection, investigation, mitigation, resolution, root cause. Write for someone reviewing this incident months later."},"formatting":["Headings: separate Timeline, Impact, Root Cause, Remediation, Lessons Learned","Bullet lists: action items, affected services, contributing factors","Bold: highlight timestamps, severity changes, and key decisions","Code blocks: error messages, log snippets, commands run during mitigation","Tables: impact metrics (requests affected, error rate, duration)"],"avoid":["Blame-oriented language targeting individuals","Vague impact descriptions like \"some users affected\"","Missing timeline of key events","Omitting remediation steps or follow-up actions"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":15,"max":200},"content":{"min":100,"max":15000},"sourceAi":{"min":1,"max":100}}', datetime('now'));

-- Site actions (incidents)
INSERT OR IGNORE INTO `site_actions` (`id`, `name`, `slug`, `description`, `fields`, `settings`, `status`, `created_at`, `updated_at`) VALUES ('d2f50cc2-a2aa-425b-8dce-55f3d8622110', 'Report Incident', 'report-incident', 'Report a service issue or outage', '[{"name":"name","type":"text","label":"Name","required":true,"placeholder":"Your name","maxLength":100},{"name":"email","type":"email","label":"Email","required":true,"placeholder":"you@example.com"},{"name":"severity","type":"select","label":"Severity","required":true,"options":["P0 — Critical","P1 — Major","P2 — Minor","P3 — Low"]},{"name":"affected_service","type":"select","label":"Affected Service","required":true,"options":["API Gateway","Database","Authentication","CDN","Other"]},{"name":"description","type":"textarea","label":"Incident Description","required":true,"placeholder":"Describe the issue, when it started, and any error messages...","maxLength":2000}]', '{"success_message":"Incident report received! Our team will investigate immediately.","require_honeypot":true}', 'active', '2026-03-27T01:22:49.500Z', '2026-03-27T01:22:49.500Z');
